module pipelined_multiplier (
    input clk,
    input [3:0] a, // 4-bit input a
    input [3:0] b, // 4-bit input b
    output reg [7:0] result // 8-bit output result
);
    reg [7:0] intermediate_product;

    // Stage 1: Compute the product
    always @(posedge clk) begin
        intermediate_product <= a * b; // Multiply inputs
    end

    // Stage 2: Output the product
    always @(posedge clk) begin
        result <= intermediate_product; // Pass intermediate product to output
    end
endmodule
